diff --git a/app/src/server/agents/architect/prompt.ts b/app/src/server/agents/architect/prompt.ts
index f28f23e..6393041 100644
--- a/app/src/server/agents/architect/prompt.ts
+++ b/app/src/server/agents/architect/prompt.ts
@@ -100,7 +100,15 @@ export async function buildArchitectSystemPrompt(input: {
     "",
     "6. SUGGEST WORK ITEMS when you identify gaps, risks, or next steps. Use suggest_work_items to propose concrete tasks, features, or projects in batches of 2-5. Check the graph first to avoid duplicates.",
     "",
-    "7. BE OPINIONATED. You're not a yes-machine. If the user's plan has a flaw, say so directly:",
+    "7. CREATE SUGGESTIONS for strategic proposals. Use create_suggestion when you spot:",
+    "   - An optimization opportunity (merging overlapping work, better sequencing)",
+    "   - A risk the user hasn't acknowledged (missing fallback, single point of failure)",
+    "   - A conflict between decisions or entities already in the graph",
+    "   - A missing element (no pricing model, no distribution strategy, no data model)",
+    "   - A pivot worth considering based on what you've learned",
+    "   Suggestions are agent-to-human proposals that appear in the user's feed. Link evidence_entity_ids to the observations, decisions, and entities that support your rationale.",
+    "",
+    "8. BE OPINIONATED. You're not a yes-machine. If the user's plan has a flaw, say so directly:",
     '   - "That pricing model won\'t work for enterprise buyers. Here\'s why."',
     '   - "You\'re trying to build two products at once. Pick one."',
     '   - "This is a feature, not a product. Who\'s paying for just this?"',
diff --git a/app/src/server/agents/architect/tools.ts b/app/src/server/agents/architect/tools.ts
index c7c9dae..dbca40d 100644
--- a/app/src/server/agents/architect/tools.ts
+++ b/app/src/server/agents/architect/tools.ts
@@ -2,6 +2,7 @@ import { createCheckConstraintsTool } from "../../chat/tools/check-constraints";
 import { createCreateObservationTool } from "../../chat/tools/create-observation";
 import { createCreateProvisionalDecisionTool } from "../../chat/tools/create-provisional-decision";
 import { createCreateQuestionTool } from "../../chat/tools/create-question";
+import { createCreateSuggestionTool } from "../../chat/tools/create-suggestion";
 import { createCreateWorkItemTool } from "../../chat/tools/create-work-item";
 import { createGetEntityDetailTool } from "../../chat/tools/get-entity-detail";
 import { createGetProjectStatusTool } from "../../chat/tools/get-project-status";
@@ -21,6 +22,7 @@ export function createArchitectTools(deps: ChatToolDeps) {
     create_observation: createCreateObservationTool(deps),
     suggest_work_items: createSuggestWorkItemsTool(deps),
     create_work_item: createCreateWorkItemTool(deps),
+    create_suggestion: createCreateSuggestionTool(deps),
     update_question: createUpdateQuestionTool(deps),
   };
 }
diff --git a/tests/unit/architect-agent.test.ts b/tests/unit/architect-agent.test.ts
index edeb68a..3232bc9 100644
--- a/tests/unit/architect-agent.test.ts
+++ b/tests/unit/architect-agent.test.ts
@@ -27,6 +27,7 @@ describe("architect agent tools", () => {
     expect(toolNames).toContain("create_observation");
     expect(toolNames).toContain("suggest_work_items");
     expect(toolNames).toContain("create_work_item");
+    expect(toolNames).toContain("create_suggestion");
     expect(toolNames).toContain("update_question");
   });

@@ -43,13 +44,12 @@ describe("architect agent tools", () => {
     expect(toolNames).not.toContain("resolve_observation");
     expect(toolNames).not.toContain("resolve_decision");
     expect(toolNames).not.toContain("confirm_decision");
-    expect(toolNames).not.toContain("create_suggestion");
     expect(toolNames).not.toContain("show_relationship_graph");
   });

-  it("has exactly 10 tools", () => {
+  it("has exactly 11 tools", () => {
     const tools = createArchitectTools(mockDeps);
-    expect(Object.keys(tools)).toHaveLength(10);
+    expect(Object.keys(tools)).toHaveLength(11);
   });
 });

